/**
 * Unremovable Plugin
 * Prevents deletion of items marked with 'unremovable: true' in their data
 */
function plugin()
{
    const self = this;

    // Override the render function to add 'unremovable' class to items
    this.hook('after', 'setupTemplates', () => {
        const originalRender = self.settings.render.item;

        self.settings.render.item = function (data, escape) {
            const item = self.options[data.value] || data;

            // Call the original render function
            let result = originalRender.call(self, data, escape);

            // If the item is marked as unremovable, add the class
            if (item.unremovable && result && result.classList) {
                // Add the class
                result.classList.add('unremovable');
            }

            return result;
        };
    });

    // Hook into removeItem to prevent deletion of unremovable items (for remove button clicks)
    const originalRemoveItem = self.removeItem;

    this.hook('instead', 'removeItem', (item, silent) => {
        const itemObj = self.getItem(item);

        // If the item is unremovable, don't delete it
        if (itemObj && itemObj.classList && itemObj.classList.contains('unremovable')) {
            return false;
        }

        // Otherwise, call the original removeItem
        return originalRemoveItem.call(self, item, silent);
    });
}

export { plugin as default };
