import TomSelect from 'tom-select/base';
import './tom-select.css'
import './plugins/plugins.js';

/**
 * jQuery plugin wrapper for tom-select with selectize API compatibility
 */
(function($) {
    'use strict';

    /**
     * Default options for TomSelect instances
     */
    const DEFAULT_OPTIONS = {
        hidePlaceholder: true,
        dataAttr: 'data',
        render: {
            loading: () => null,
            'no_results': () => {
                return '<div class="no-results">' + Lang.get('messages.no_results') + '</div>';
            },
            'option_create': (data, escape) => {
                return '<div class="create">' + Lang.get('core.add_selectize', {'item': escape(data.input)}) + '</div>';
            },
        }
    };

    /**
     * Adds the 'load_fn' plugin to the plugins configuration
     * @param {Array|Object} plugins - Existing plugins configuration
     * @returns {Array|Object} - Updated plugins configuration
     */
    function addLoadFnPlugin(plugins) {
        if (Array.isArray(plugins)) {
            return [...plugins, 'load_fn'];
        } else if (typeof plugins === 'object') {
            return { ...plugins, load_fn: {} };
        }
        return ['load_fn'];
    }

    /**
     * Merges user options with default options
     * @param {Object} userOptions - User-provided options
     * @returns {Object} - Merged options
     */
    function mergeOptions(userOptions) {
        const options = {
            ...DEFAULT_OPTIONS,
            ...userOptions,
            render: {
                ...DEFAULT_OPTIONS.render,
                ...(userOptions.render || {})
            }
        };

        // Handle plugins separately to ensure load_fn is added
        options.plugins = addLoadFnPlugin(userOptions.plugins);

        return options;
    }

    /**
     * Main selectize method - creates a TomSelect instance wrapped with Selectize API
     * @param {Object} options - Configuration options (selectize format)
     * @returns {jQuery} - jQuery object for chaining
     */
    $.fn.selectize = function(options) {
        return this.each(function() {
            const $el = $(this);

            // Skip if already initialized
            if (this.selectize || this.tomselect) {
                return;
            }

            // Merge user options with defaults
            const mergedOptions = mergeOptions(options || {});

            // Initialize tom-select
            this.tomselect = this.selectize = new TomSelect(this, mergedOptions);
            $el.data('selectize', this.tomselect);
        });
    };
})(jQuery);
