/**
 * Backwards compatibility plugin for Selectize's load(function(callback) {...}) pattern.
 *
 * In Selectize.js, you could call: selectize.load(function(callback) { callback(data); })
 * In Tom-Select, load(query) expects a string and invokes settings.load internally.
 *
 * This plugin detects when load() is called with a function and executes it
 * with a callback that adds options to the control.
 */
function plugin()
{
    const original_load = this.load;

    this.hook('instead', 'load', function (arg) {
        const self = this;

        // If arg is a function, use the old Selectize-style behavior
        if (typeof arg === 'function') {
            const callback = function (data) {
                self.loadCallback(data, {});
            };

            // Call the provided function with our callback
            arg.call(self, callback);

            return;
        }

        // Otherwise, use Tom-Select's native load behavior
        return original_load.call(self, arg);
    });
}

export { plugin as default };
